from dataclasses import dataclassfrom .detector import Detector@dataclass(slots=True)class Order:    """    One CRIRES+ echelle order.    """    number: int    detector1: Detector    detector2: Detector    detector3: Detector    def __iter__(self):                return iter(            (                self.detector1,                self.detector2,                self.detector3,            )        )    '''    Properties    '''    @property    def detectors(self):        return list(self)    @property    def wavelength_min(self):        return min(            detector.wavelength_min            for detector in self        )    @property    def wavelength_max(self):        return max(            detector.wavelength_max            for detector in self        )    @property    def wavelength_range(self):        return (            self.wavelength_min,            self.wavelength_max,        )        @property    def width(self):        return (            self.wavelength_max -            self.wavelength_min        )    '''    Methods    '''    def __str__(self):        return (            f"Order {self.number}"        )